from __future__ import annotations


import pytest

from paycli import transactions as tx
from paycli.report import export_report


# ---------------------------------------------------------------------------
# BUG-A: inclusive daily-limit boundary
# ---------------------------------------------------------------------------

def test_bug_a_boundary_exactly_at_limit_is_allowed():
    """BUG-A: spent + amount == limit must return True (inclusive <=).

    FIRST: Fast (pure arithmetic), Independent (no shared state),
    Repeatable (deterministic inputs), Self-validating (assert),
    Timely (written to lock in the fix before this lands in prod).

    Uses inputs (0.0, 50.0, 50.0) -- different from baseline (60,40,100)
    to exercise the zero-spent edge of the boundary.
    """
    result = tx.is_within_daily_limit(spent=0.0, amount=50.0, limit=50.0)
    assert result is True


def test_bug_a_boundary_one_cent_over_limit_is_rejected():
    """BUG-A: spent + amount == limit + 0.01 must return False.

    FIRST: Fast, Independent, Repeatable, Self-validating, Timely.

    Complements the at-limit test; baseline covers (60,41,100) but not
    the minimal overshoot from zero-spent.
    """
    result = tx.is_within_daily_limit(spent=0.0, amount=50.01, limit=50.0)
    assert result is False


